frame_eqs:
dec_m = pow (0.8, 30/fps); dec_s = pow (0.9, 30/fps);

beat = max (max (bass, mid), treb);
avg = avg*dec_s + beat*(1-dec_s);
is_beat = above(beat, .2+avg+peak) * above (time, t0+.2);
t0 = is_beat*time + (1-is_beat)*t0;
peak = is_beat * beat + (1-is_beat)*peak*dec_m;
index = (index + is_beat) %16;

q20 = avg;
q21 = beat;
q22 = peak;
q23 = index;
q24 = is_beat;
q26 = bass + mid + treb;

k1 =  is_beat*equal(index,0);
p1 =  p1*dec_m + (1-dec_m)*cos(time/3);
p2 =  p2*dec_m + (1-dec_m)*p1;
p3 =  p3*dec_m + (1-dec_m)*p2;
rott =  rott*dec_s + (1-dec_s)*p3;

//puls = puls*dec_m + (1-dec_m)*(beat/avg);

zoom = 1+0.25*q20*puls;
rot = rott/128 * (normal+index/4);
cx = .5 + .5*sin(time/9);
cy = .5 + .5*sin(time/7);

q1 = cos(rott);
q2 = sin(rott);
q3 = -q2;
q4 = q1;

normal = 1- above(index,7)*above(q20,1.8);
monitor = normal;

wave_0_per_point:
// lorenz-attractor based code

dx = .866*(bass_att - mid_att)*sample*.1/(.5*(1-pow(2,-22*abs(sample-.5))));
dy = -.5*(bass_att - mid_att)*sample*.1/(.5*(1-pow(2,-22*abs(sample-.5))));

//dissipation
dd = sqrt(dx*dx + dy*dy);
dz = -.01*dd;

//inertia
df = .1;
dx = dx*(1-df) + dz*df;
dy = dy*(1-df) + dz*df;

//integration
dz = dz + .1*sin(time*.7);

x = .5 + dx;
y = .5 + dy;

//phase compensation
c = sqrt(dx*dx + dy*dy);
s = atan2(dx,dy);
t1 += c*cos(s);
t2 += c*sin(s);

//phase comparison & scaling
scale = 2;
s1 = t4 - scale*t1;
s2 = t3 - scale*t2;
t4 += s1;
t3 += s2;

//additive wave
a = .5;
b = .75 + (s1-s2)*.1;
r = .25 - (s1+s2)*.05;

